// Unwrap the webhook body so downstream nodes can read the Discord
// payload fields at the top level — matches the shape the Channel Router
// was originally written against.
const item = $input.item.json || {};
const body = item.body || item;
return [{ json: body }];

// ---------------------------------------------------------------------------
// Channel Router
//
// Reads the incoming Discord message (from discord-relay via Unwrap Body),
// decides whether Bruce should respond, detects /use commands, and chooses
// which Claude model to call.
//
// This Code node does NOT execute SQL itself — n8n Code nodes can't.
// Surrounding nodes handle the Postgres parts:
//
//   Upstream (optional, improves UX):
//     "Fetch User Preference" — Postgres node between "Ignore Bots" and
//     "Channel Router". Query:
//       SELECT model FROM user_model_preferences
//        WHERE discord_user_id = $1 AND channel_id = $2
//       LIMIT 1
//     Params: {{ $json.author.id }}, {{ $json.channel_id }}
//
//   Downstream (for /use command persistence):
//     "Is /use command?" IF node → branches on $json.isUseCommand === true
//       true → "Save User Preference" (Postgres, UPSERT or DELETE depending
//              on useReset) → "Reply /use Confirmation" (Discord node,
//              posts $json.useReply)
//       false → existing "Should Respond?" IF node (unchanged downstream)
//
// Keep the ROUTING table in sync with config/channel-routing.json.
// ---------------------------------------------------------------------------

const DEFAULT_MODEL = 'claude-sonnet-4-6';

// Short aliases users can type with /use <alias>.
const MODEL_SHORTCUTS = {
  haiku:  'claude-haiku-4-5-20251001',
  sonnet: 'claude-sonnet-4-6',
  opus:   'claude-opus-4-6',
};

const ROUTING = {
  'general':        { behavior: 'mention-only', persona: 'general',        model: 'claude-haiku-4-5-20251001' },
  'family':         { behavior: 'mention-only', persona: 'family',         model: 'claude-sonnet-4-6' },
  'announcements':  { behavior: 'read-only',    persona: null,             model: null },
  'fig':            { behavior: 'always',       persona: 'fig',            model: 'claude-opus-4-6' },
  'jake-personal':  { behavior: 'always',       persona: 'jake-personal',  model: 'claude-sonnet-4-6' },
  'jake-ask':       { behavior: 'always',       persona: 'ask',            model: 'claude-haiku-4-5-20251001' },
  'travel':         { behavior: 'mention-only', persona: 'travel',         model: 'claude-sonnet-4-6' },
  'food':           { behavior: 'always',       persona: 'food',           model: 'claude-sonnet-4-6' },
  'cps':            { behavior: 'mention-only', persona: 'cps',            model: 'claude-sonnet-4-6' },
  'loubi-personal': { behavior: 'always',       persona: 'loubi-personal', model: 'claude-sonnet-4-6' },
  'wis':            { behavior: 'always',       persona: 'wis',            model: 'claude-sonnet-4-6' },
  'loubi-ask':      { behavior: 'always',       persona: 'ask',            model: 'claude-haiku-4-5-20251001' },
  'joce-personal':  { behavior: 'always',       persona: 'joce-personal',  model: 'claude-sonnet-4-6' },
  'joce-school':    { behavior: 'always',       persona: 'joce-school',    model: 'claude-sonnet-4-6' },
  'joce-ask':       { behavior: 'always',       persona: 'ask',            model: 'claude-haiku-4-5-20251001' },
  'nana-personal':  { behavior: 'always',       persona: 'nana-personal',  model: 'claude-sonnet-4-6' },
  'nana-ask':       { behavior: 'always',       persona: 'ask',            model: 'claude-haiku-4-5-20251001' },
};

// Short stub personas — REPLACE each string with the full content of the
// matching prompts/channel-personas/<slug>.md file. Kept short here so the
// workflow JSON stays small; paste the full markdown between the backticks.
const PERSONAS = {
  'general': `You are Bruce, the household's shared AI assistant in #general. Audience: Jake, Loubi, Joce, Nana. Tone: warm, friendly, conversational. Only respond when @mentioned or replied to. Be concise. If a question belongs in a private channel, suggest moving there. Don't leak context from private channels.`,

  'family': `You are Bruce helping the household in #family. Audience: Jake, Loubi, Joce, Nana. Tone: practical, structured, warm. Only respond when @mentioned or replied to. When planning: summarize, list open questions, propose a next step. Ask for specifics before assuming. Be honest about what you can and can't do.`,

  'fig': `You are Bruce, Jake's work assistant in #fig. Jake is an Account Executive at Foundation Insurance Group (FIG). Respond to every message. Help with: client meeting prep, outreach drafts, account strategy, objection handling, call note summaries. Treat everything as confidential. Match Jake's register. When Jake shares notes: return a 3-bullet summary, open questions, and next steps. Keep email drafts under 120 words.`,

  'jake-personal': `You are Bruce, Jake's personal assistant in #jake-personal. Private channel. Respond to every message. Tone: frank, curious, lightly challenging. Jake wants a thought partner, not a cheerleader. Push back when reasoning is thin. Ask clarifying questions before jumping in. On health/medical: share what you know but point him to a professional. On learning projects: offer concrete next actions.`,

  'ask': `You are Bruce in a quick-answer channel. Be fast and concise. Get to the answer immediately — no preamble, no over-explanation. Use bullet points over paragraphs. If the question genuinely needs deeper thought, say so briefly and suggest moving to a personal channel, but still give your best short answer.`,

  'travel': `You are Bruce in #travel, Jake and Loubi's trip planning channel. Help with itineraries, flight and hotel tradeoffs, packing lists, visa requirements, and budget planning. Before drafting anything detailed, ask about travel style (adventure vs relaxation), rough budget, and dates. Both Jake and Loubi use this channel together — phrase responses so they land for both.`,

  'food': `You are Bruce in #food, Jake and Loubi's meal planning and recipe channel. Help with weekly meal planning, recipes, grocery lists, and restaurant recommendations. For meal planning: ask about dietary preferences, how many people eating, and the week's schedule before proposing a plan. For recipes: clear ingredient lists and concise steps. Note: Jake enjoys grilling proteins. Keep suggestions practical for a busy household.`,

  'cps': `You are Bruce in #cps, the Capital Petsitters operations channel. Jake and Nana run CPS together. Respond only when @mentioned. Tone: operational, clear, actionable. For scheduling/client issues: ask for the specific case before reasoning. For policy questions: reference existing policy or flag that you're proposing a new one. For staff issues: be discreet and neutral. For pricing: think in concrete ranges and tradeoffs.`,

  'loubi-personal': `You are Bruce, Loubi's personal assistant in #loubi-personal. Private channel. Respond to every message. Tone: warm, attentive, thoughtful. Listen before advising. Match her register — if she's venting, don't problem-solve until asked. Ask clarifying questions before giving structured advice. Keep everything from this channel private.`,

  'wis': `You are Bruce, Loubi's work assistant in #wis. Loubi works at Washington International School (WIS). Respond to every message. Tone: collegial and crisp. Ask about grade level, subject, and context before drafting anything. For lesson planning: use objective → activities → assessment structure. For parent/colleague communication: warm, clear, concise. Never invent citations.`,

  'joce-personal': `You are Bruce, Joce's personal assistant in #joce-personal. Joce is a high-school student. Private channel. Respond to every message. Tone: friendly, age-appropriate, real. Don't talk down. Listen first — if she's processing something, don't immediately solve. For social questions: ask context before advising. Be honest. For anything touching safety (mental health, substances, unsafe relationships): be supportive but always point to a trusted adult. Keep this channel private.`,

  'joce-school': `You are Bruce in #joce-school, Joce's homework channel. Respond to every message. Be a tutor, not an answer key. Never just give answers — walk through thinking, ask what she's tried. For writing: never write the essay for her. Offer outlines and feedback. For math/science: explain steps, stop at junctions and ask what she'd do next. For test prep: quiz her. Hard rules: never write a paper she'll submit as her own, never give just the answer to graded work.`,

  'nana-personal': `You are Bruce, Nana's personal assistant in #nana-personal. Private channel. Respond to every message. Tone: warm, respectful, patient. Ask what kind of help she wants before launching in. For tasks: be concrete and step-oriented. For personal reflection: listen first, advise only if asked. For health questions: share what you know but always point to her doctor. Keep this channel private.`,
};

// ---------------------------------------------------------------------------
// Parse incoming message
//
// Upstream of this node is "Fetch user Preference" (Postgres), whose output
// is a preference row — NOT the Discord body. Reach back to "Unwrap Body"
// explicitly so we're always reading the Discord payload.
// ---------------------------------------------------------------------------
const msg = $('Unwrap Body').first().json;

const channelName = msg.channel_name || (msg.channel && msg.channel.name) || '';
const channelId   = msg.channel_id   || (msg.channel && msg.channel.id)   || '';
const messageId   = msg.id           || msg.message_id                     || '';
const userId      = (msg.author && msg.author.id) || msg.author_id || '';
const content     = (msg.content || '').trim();
const mentions    = (msg.mentions || []).map(m => m.id || m);
const botMentioned = mentions.includes($env.DISCORD_BOT_USER_ID);
const isReplyToBot =
  msg.referenced_message &&
  msg.referenced_message.author &&
  msg.referenced_message.author.id === $env.DISCORD_BOT_USER_ID;

const route = ROUTING[channelName] || { behavior: 'read-only', persona: null, model: null };

// ---------------------------------------------------------------------------
// /use command detection
//   /use haiku|sonnet|opus    → expand shortcut, upsert preference
//   /use <full-model-string>  → upsert preference as-is
//   /use default              → delete preference, reset to channel default
//   /use                      → print usage help
// ---------------------------------------------------------------------------
let isUseCommand = false;
let useNewModel  = null;   // model string to upsert; null if reset/help
let useReset     = false;  // true → delete the pref row
let useReply     = null;   // confirmation text posted back to Discord

if (/^\/use(\s|$)/i.test(content)) {
  isUseCommand = true;
  const arg = content.replace(/^\/use\s*/i, '').trim();

  if (!arg) {
    useReply = 'Usage: `/use <model>` — shortcuts: `haiku`, `sonnet`, `opus`. Or `/use default` to reset to this channel\'s default.';
  } else if (arg.toLowerCase() === 'default') {
    useReset = true;
    const resetTo = route.model || DEFAULT_MODEL;
    useReply = `Reset — using the channel default for #${channelName}: \`${resetTo}\`.`;
  } else {
    const lower = arg.toLowerCase();
    useNewModel = MODEL_SHORTCUTS[lower] || arg;
    useReply = `Switched to \`${useNewModel}\` in this channel. Use \`/use default\` to reset.`;
  }
}

// ---------------------------------------------------------------------------
// Response gating
// ---------------------------------------------------------------------------
let shouldRespond = false;
if (route.behavior === 'always')       shouldRespond = true;
if (route.behavior === 'mention-only') shouldRespond = botMentioned || isReplyToBot;
if (route.behavior === 'read-only')    shouldRespond = false;

// /use commands short-circuit the Claude call — they reply with the
// confirmation text instead.
if (isUseCommand) shouldRespond = false;

// ---------------------------------------------------------------------------
// Resolve effective model:
//   user preference (if upstream Fetch node returned one) > channel default > fallback
// ---------------------------------------------------------------------------
let userPreference = null;
try {
  const prefItems = $('Fetch user Preference').all();
  if (prefItems.length && prefItems[0].json && prefItems[0].json.model) {
    userPreference = prefItems[0].json.model;
  }
} catch (_) {
  // "Fetch User Preference" node doesn't exist yet — ignore.
}

const modelDefault = route.model || DEFAULT_MODEL;
const model        = userPreference || modelDefault;

return [{
  json: {
    // routing outputs
    shouldRespond,
    channelId,
    channelName,
    messageId,
    userId,
    content,
    behavior: route.behavior,
    persona: route.persona,
    systemPrompt: route.persona ? (PERSONAS[route.persona] || '') : '',

    // model selection outputs
    model,
    modelDefault,
    userPreference,

    // /use command outputs (consumed by downstream Save + Reply branch)
    isUseCommand,
    useNewModel,
    useReset,
    useReply,
  }
}];

// Build the Anthropic /v1/messages request body.
//
// Model selection comes from the Channel Router:
//   router.model = user preference (if any) > channel default > hardcoded fallback
//
// Conversation history came back newest-first from Postgres; reverse it
// before feeding to Claude, which expects oldest-first.

const router = $('Channel Router').first().json;
const rows   = $input.all().map(i => i.json).reverse();

const messages = rows
  .filter(r => r.role === 'user' || r.role === 'assistant')
  .map(r => ({ role: r.role, content: r.content }));

messages.push({ role: 'user', content: router.content });

return [{
  json: {
    ...router,
    requestBody: {
      model: router.model || $env.ANTHROPIC_MODEL || 'claude-sonnet-4-6',
      max_tokens: 1024,
      system: router.systemPrompt,
      messages,
    },
  }
}];

// Extract Claude's reply text and prep the fields needed downstream.
const router = $('Channel Router').first().json;
const apiRes = $input.item.json;

const reply = (apiRes.content || [])
  .filter(c => c.type === 'text')
  .map(c => c.text)
  .join('\n\n')
  .trim();

if (!reply) {
  throw new Error('Empty reply from Claude — check response shape: ' + JSON.stringify(apiRes).slice(0, 500));
}

return [{
  json: {
    ...router,
    reply,
    // Discord caps message length at 2000 chars; truncate safely.
    replyTruncated: reply.length > 1950 ? reply.slice(0, 1950) + '…' : reply,
  }
}];

parameters.query:
DELETE FROM user_model_preferences
WHERE discord_user_id = '{{ $json.userId }}'
  AND channel_id = '{{ $json.channelId }}';
